import{_ as a,o as t,c as r,ak as o}from"./chunks/framework.CDHwDzB5.js";const m=JSON.parse('{"title":"Event 键值对格式","description":"","frontmatter":{},"headers":[],"relativePath":"TTHSDNext/TTHSD_Docs/zh/event/event-format.md","filePath":"TTHSDNext/TTHSD_Docs/zh/event/event-format.md","lastUpdated":0}'),n={name:"TTHSDNext/TTHSD_Docs/zh/event/event-format.md"};function l(i,e,s,d,c,h){return t(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="event-键值对格式" tabindex="-1">Event 键值对格式 <a class="header-anchor" href="#event-键值对格式" aria-label="Permalink to “Event 键值对格式”">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to “概述”">​</a></h2><p>Event事件采用标准的键值对格式进行数据传输，每个事件包含两个核心字段：<code>Type</code>和<code>Name</code>，用于标识事件类型和来源。</p><h2 id="字段详细说明" tabindex="-1">字段详细说明 <a class="header-anchor" href="#字段详细说明" aria-label="Permalink to “字段详细说明”">​</a></h2><h3 id="type-字段" tabindex="-1">Type 字段 <a class="header-anchor" href="#type-字段" aria-label="Permalink to “Type 字段”">​</a></h3><ul><li><strong>字段描述</strong>：标识当前事件的具体类型和用途</li><li><strong>数据类型</strong>：字符串（String）</li><li><strong>可选值</strong>：&#39;start&#39; | &#39;startOne&#39; | &#39;update&#39; | &#39;end&#39; | &#39;endOne&#39; | &#39;msg&#39; | &#39;err&#39;</li><li><strong>值含义</strong>： <ul><li><strong>start</strong>：表示整个下载任务组开始执行</li><li><strong>startOne</strong>：表示单个下载任务开始执行</li><li><strong>update</strong>：表示下载进度状态更新</li><li><strong>endOne</strong>：表示单个下载任务执行完成</li><li><strong>end</strong>：表示整个下载任务组执行结束</li><li><strong>msg</strong>：表示发送消息通知</li><li><strong>err</strong>：表示发送错误通知</li></ul></li></ul><h3 id="name-字段" tabindex="-1">Name 字段 <a class="header-anchor" href="#name-字段" aria-label="Permalink to “Name 字段”">​</a></h3><ul><li><strong>字段描述</strong>：事件的名称或简要描述（例如中文描述文本）</li><li><strong>数据类型</strong>：字符串（String）</li></ul><h3 id="showname-字段" tabindex="-1">ShowName 字段 <a class="header-anchor" href="#showname-字段" aria-label="Permalink to “ShowName 字段”">​</a></h3><ul><li><strong>字段描述</strong>：用于展示给用户的任务/会话名称（友好显示名）</li><li><strong>数据类型</strong>：字符串（String）</li></ul><h3 id="id-字段" tabindex="-1">ID 字段 <a class="header-anchor" href="#id-字段" aria-label="Permalink to “ID 字段”">​</a></h3><ul><li><strong>字段描述</strong>：任务或条目的唯一标识符（例如任务ID）</li><li><strong>数据类型</strong>：字符串（String）</li></ul><blockquote><p>说明：源码中 <code>Event</code> 结构包含 <code>Type</code>, <code>Name</code>, <code>ShowName</code>, <code>ID</code> 四个字段，接收方在使用时应同时关注 <code>ShowName</code> 和 <code>ID</code> 以定位具体任务或显示名。</p></blockquote><h2 id="使用规范" tabindex="-1">使用规范 <a class="header-anchor" href="#使用规范" aria-label="Permalink to “使用规范”">​</a></h2><ol><li><strong>数据格式</strong>：采用 UTF-8 编码的 JSON 格式传输</li><li><strong>字段验证</strong>：接收方应验证 Type 字段的合法性</li><li><strong>兼容性</strong>：新版本可能增加新的事件类型，建议实现向前兼容</li></ol>',15)])])}const p=a(n,[["render",l]]);export{m as __pageData,p as default};
